-- BƯỚC 0: TẮT TRIGGER ĐỂ XÓA + INSERT THOẢI MÁI
-- ============================================================
BEGIN
    FOR trg IN (SELECT trigger_name FROM user_triggers) LOOP
        EXECUTE IMMEDIATE 'ALTER TRIGGER ' || trg.trigger_name || ' DISABLE';
    END LOOP;
END;
