-- ============================================================
-- BƯỚC 1.5: BẬT LẠI TRIGGER
-- ============================================================
BEGIN
    FOR trg IN (SELECT trigger_name FROM user_triggers) LOOP
        EXECUTE IMMEDIATE 'ALTER TRIGGER ' || trg.trigger_name || ' ENABLE';
        BEGIN EXECUTE IMMEDIATE 'ALTER TRIGGER ' || trg.trigger_name || ' COMPILE'; EXCEPTION WHEN OTHERS THEN NULL; END;
    END LOOP;
END;
/

