-- ============================================================
-- 21. TÍNH LẠI TỔNG TIỀN HÓA ĐƠN & PHIẾU NHẬP
-- ============================================================
UPDATE HOA_DON hd
SET hd.TONGTIEN = (
    NVL((SELECT SUM(SOLUONG * DONGIA) FROM CT_HOA_DON WHERE MAHD = hd.MAHD), 0) +
    NVL((SELECT SUM(SOLUONG * DONGIA) FROM CT_HOA_DON_DV WHERE MAHD = hd.MAHD), 0)
);

UPDATE PHIEU_NHAP pn
SET pn.TONGTIEN = (
    SELECT NVL(SUM(SOLUONGNHAP * GIANHAP), 0) FROM LO_HANG WHERE MAPN = pn.MAPN
);

-- Đồng bộ tồn kho sau khi bán
MERGE INTO LO_HANG lh
USING (
    SELECT MALO, SUM(SOLUONG) AS SOLD_QTY
    FROM CT_HOA_DON
    GROUP BY MALO
) sold ON (lh.MALO = sold.MALO)
WHEN MATCHED THEN UPDATE SET lh.SOLUONGTON = lh.SOLUONGNHAP - sold.SOLD_QTY;

-- Đồng bộ NULL
UPDATE LO_HANG SET SOLUONGTON = SOLUONGNHAP WHERE SOLUONGTON IS NULL;

COMMIT;

