-- 22. KIỂM TRA KẾT QUẢ SEED
-- ============================================================
SELECT 'TỔNG NHÂN SỰ: '       || COUNT(*) FROM NHAN_SU     WHERE IS_DELETED = 0
UNION ALL SELECT 'TỔNG KHÁCH HÀNG: '   || COUNT(*) FROM KHACH_HANG  WHERE IS_DELETED = 0
UNION ALL SELECT 'TỔNG SẢN PHẨM: '     || COUNT(*) FROM SAN_PHAM
UNION ALL SELECT 'TỔNG LÔ HÀNG: '      || COUNT(*) FROM LO_HANG
UNION ALL SELECT 'TỔNG HỒ SƠ THỊ LỰC: ' || COUNT(*) FROM HO_SO_THI_LUC
UNION ALL SELECT 'TỔNG PHIẾU KÊ ĐƠN: '  || COUNT(*) FROM PHIEU_KE_DON
UNION ALL SELECT 'TỔNG HÓA ĐƠN: '      || COUNT(*) FROM HOA_DON
UNION ALL SELECT 'TỔNG DOANH THU: '     || TO_CHAR(NVL(SUM(SOTIEN),0), '999,999,999,999') FROM THANH_TOAN WHERE TRANGTHAI = N'Hoàn thành'
UNION ALL SELECT 'TỔNG ĐÁNH GIÁ: '     || COUNT(*) FROM DANH_GIA
UNION ALL SELECT 'TỔNG KHUYẾN MÃI: '   || COUNT(*) FROM KHUYEN_MAI
UNION ALL SELECT 'TỔNG LỊCH HẸN: '     || COUNT(*) FROM LICH_HEN
UNION ALL SELECT 'TỔNG XỬ LÝ KÍNH: '   || COUNT(*) FROM XU_LY_KINH;